Bash(cd "F:/1work/农业能源环境/web" && node -e "
const icons = require\('@arco-design/web-vue/es/icon'\);
const available = new Set\(Object.keys\(icons\)\);
const fs = require\('fs'\);
const path = require\('path'\);

const viewsDir = 'src/views';
const files = fs.readdirSync\(viewsDir\).filter\(f => f.endsWith\('.vue'\)\);

files.forEach\(file => {
  const content = fs.readFileSync\(path.join\(viewsDir, file\), 'utf8'\);
  const matches = content.match\(/Icon[A-Za-z]+/g\) || [];
  const unique = [...new Set\(matches\)];
  const missing = unique.filter\(icon => !available.has\(icon\)\);
  if \(missing.length\) console.log\(file + ': MISSING ' + missing.join\(', '\)\);
}\);
" 2>&1)

